-- 1. subjects (no dependencies)
CREATE TABLE public.subjects (
  id   text PRIMARY KEY,
  name text,
  code text
);

-- 2. teachers (no dependencies at creation)
CREATE TABLE public.teachers (
  id         text PRIMARY KEY,
  name       text,
  email      text UNIQUE,
  role       text,
  subject    text,
  class_id   text,
  phone      text,
  join_date  date,
  avatar     text,
  subject_id text,
  message    text,
  bio        text
);

-- 3. classes (no dependencies at creation)
CREATE TABLE public.classes (
  id         text PRIMARY KEY,
  name       text,
  grade      integer,
  section    text,
  room       text,
  teacher_id text
);

-- 4. students (no dependencies at creation)
CREATE TABLE public.students (
  id             text PRIMARY KEY,
  name           text,
  email          text UNIQUE,
  role           text,
  roll           integer,
  class_id       text,
  gender         text,
  dob            date,
  phone          text,
  guardian       text,
  guardian_phone text,
  address        text,
  avatar         text
);

-- 5. periods (no dependencies)
CREATE TABLE public.periods (
  id         text PRIMARY KEY,
  sort_order integer NOT NULL,
  start_time text NOT NULL,
  end_time   text NOT NULL,
  is_break   boolean DEFAULT false,
  label      text
);

-- 6. exams (no dependencies)
CREATE TABLE public.exams (
  id         text PRIMARY KEY,
  name       text NOT NULL,
  start_date date,
  end_date   date,
  status     text NOT NULL DEFAULT 'upcoming',
  created_at timestamp with time zone DEFAULT now()
);

-- 7. events (depends on teachers)
CREATE TABLE public.events (
  id           text PRIMARY KEY,
  title        text NOT NULL,
  slug         text NOT NULL UNIQUE,
  excerpt      text,
  content      text,
  category     text,
  date         date,
  cover_image  text,
  author_id    text,
  published    boolean DEFAULT false,
  created_at   timestamp with time zone DEFAULT now()
);
ALTER TABLE public.events ADD COLUMN IF NOT EXISTS author_name text;

-- 8. event_images (depends on events)
CREATE TABLE public.event_images (
  id         text PRIMARY KEY,
  event_id   text,
  url        text,
  sort_order integer DEFAULT 0
);

-- 9. notices
CREATE TABLE public.notices (
  id        text PRIMARY KEY,
  title     text,
  content   text,
  category  text,
  priority  text,
  author_id text,
  date      date,
  expires   date
);

-- 10. results (depends on students, subjects, exams)
CREATE TABLE public.results (
  id         text PRIMARY KEY,
  student_id text,
  subject_id text,
  exam       text,
  marks      integer,
  total      integer,
  grade      text,
  remarks    text,
  exam_id    text
);

-- 11. attendance (depends on students)
CREATE TABLE public.attendance (
  id         text PRIMARY KEY,
  student_id text,
  date       date,
  status     text
);

-- 12. schedule (depends on classes, subjects, teachers, periods)
CREATE TABLE public.schedule (
  id         text PRIMARY KEY,
  class_id   text,
  subject_id text,
  teacher_id text,
  day        text,
  start_time text,
  end_time   text,
  room       text,
  period_id  text
);

-- 13. testimonials
CREATE TABLE public.testimonials (
  id          text PRIMARY KEY,
  name        text,
  avatar      text,
  quote       text,
  child_class text,
  active      boolean DEFAULT true
);

-- 14. admission_open
CREATE TABLE public.admission_open (
  id    text PRIMARY KEY,
  value boolean DEFAULT false
);

-- 15. superadmin (depends on auth.users)
CREATE TABLE public.superadmin (
  id    uuid PRIMARY KEY,
  email text
);
ALTER TABLE public.superadmin ADD COLUMN IF NOT EXISTS name text;

-- 16. users
CREATE TABLE public.users (
  id         text PRIMARY KEY,
  email      text NOT NULL UNIQUE,
  name       text NOT NULL,
  phone      text,
  avatar     text,
  role       text NOT NULL DEFAULT 'admin',
  address    text,
  created_at timestamp with time zone DEFAULT now()
);


