INSERT INTO public.teachers (id,name,email,role,subject,class_id,phone,join_date,avatar,subject_id,message,bio) VALUES ('ch_01','Md Mamunur Rashid','mdmamunur@greenfieldacademy.edu.bd','Chairman',NULL,NULL,'+880-1845-67891','2023-02-05','https://res.cloudinary.com/sumitdey/image/upload/q_auto/f_auto/v1775482169/avatar_man_3_c8owzj.png',NULL,'Greenfield Academy was founded on the belief that quality education is the most powerful investment a community can make. Twenty-five years on, that belief drives everything we do.',NULL);
INSERT INTO public.teachers (id,name,email,role,subject,class_id,phone,join_date,avatar,subject_id,message,bio) VALUES ('tch_07','Aminul Islam','aminul@greenfieldacademy.edu.bd','Principal',NULL,NULL,'+880-1711-000007','2005-01-01','https://res.cloudinary.com/sumitdey/image/upload/q_auto/f_auto/v1775482168/avatar_man_2_vu0obr.png',NULL,'At Greenfield Academy, we are committed to nurturing not just academic excellence, but the whole person â€” instilling values, resilience, and a lifelong love of learning in every student who walks through our doors.','With over two decades in education, our Principal leads Greenfield Academy with a firm belief that every child deserves a nurturing environment to discover their potential. Her open-door policy and commitment to academic excellence have shaped the school''s culture since 2008.');
INSERT INTO public.teachers (id,name,email,role,subject,class_id,phone,join_date,avatar,subject_id,message,bio) VALUES ('tch_02','Nasrin Akter','nasrin@greenfieldacademy.edu.bd','Vice Principal','English','cls_02','+880-1711-000002','2012-03-20','https://res.cloudinary.com/sumitdey/image/upload/q_auto/f_auto/v1775482169/avatar_woman_2_myepy1.jpg','sub_02','Our classrooms are places where curiosity is celebrated and every question matters. We work every day to ensure that each student feels seen, supported, and inspired to reach their fullest potential.','Bringing fifteen years of classroom and administrative experience, our Vice Principal oversees the day-to-day running of the school with calm authority. He works closely with teachers and parents alike to ensure every student''s journey through Greenfield is supported at every step');
