INSERT INTO public.events (id,title,slug,excerpt,content,category,date,cover_image,author_id,published,created_at,author_name) VALUES ('evt_04','Parent-Teacher Meeting â€” Spring 2024','parent-teacher-meeting-spring-2024','Parents and teachers came together for a productive morning of conversation, feedback, and shared commitment to student success.','<h2>Overview</h2><p>The Spring Parent-Teacher Meeting was held on the 30th of January 2024. Parents of students from all classes attended across two sessions, morning and afternoon, to discuss their children''s academic progress and overall wellbeing.</p><h2>Key Discussion Points</h2><p>Teachers shared midterm results, attendance records, and behavioural observations with parents. Several parents raised questions about the upcoming final examination schedule and the school''s support system for students who need additional help.</p><h2>Outcomes</h2><p>The school announced the introduction of weekly after-school study sessions for students requiring academic support. A new parent communication channel via the school portal was also announced, allowing parents to view attendance and results in real time.</p><h2>Next Meeting</h2><p>The next Parent-Teacher Meeting is scheduled for July 2024. Parents are encouraged to reach out to class teachers directly through the portal in the meantime.</p>','General','2024-01-30','https://images.unsplash.com/photo-1577896851231-70ef18881754?w=1200&auto=format&fit=crop','usr_admin_004',true,'2024-01-31 11:00:00+00',NULL);
INSERT INTO public.events (id,title,slug,excerpt,content,category,date,cover_image,author_id,published,created_at,author_name) VALUES ('evt_02','Inter-School Science Fair 2024','inter-school-science-fair-2024','Twelve schools, forty projects, and one unforgettable afternoon of discovery as young scientists presented their work to judges and peers.','<h2>Overview</h2><p>Greenfield Academy hosted the Inter-School Science Fair 2024 on the 10th of February. Forty student teams from twelve schools across Dhaka presented original science projects to a panel of judges drawn from local universities and industry.</p><h2>Highlights</h2><p>Projects spanned topics including renewable energy, water purification, artificial intelligence, and biodiversity. The standard of work on display was remarkably high, with several projects drawing praise from the judging panel for their originality and practical application.</p><h2>Greenfield Achievements</h2><p>Our own students performed exceptionally well. Sabbir Rahman and Nusrat Jahan took first place in the senior category with their project on solar-powered water filtration. Arif Hasan and Mitu Rani Das received a commendation in the junior category for their biodiversity mapping study.</p><h2>Closing Notes</h2><p>The fair was a wonderful opportunity for students to engage with science beyond the classroom and to connect with peers from across the city. We look forward to hosting again next year.</p>','Academic','2024-02-10','https://images.unsplash.com/photo-1564981797816-1043664bf78d?w=1200&auto=format&fit=crop','usr_admin_001',true,'2024-02-11 09:00:00+00',NULL);
INSERT INTO public.events (id,title,slug,excerpt,content,category,date,cover_image,author_id,published,created_at,author_name) VALUES ('evt_01','Annual Sports Day 2024','annual-sports-day-2024','A day of athletic excellence as students from all classes competed in track, field, and team events under the open sky.','<h2>Overview</h2><p>The Annual Sports Day 2024 was held on the 25th of January at the Greenfield Academy grounds. Students from Classes 9, 10, and 11 participated in a wide range of events, showcasing their athletic talent and team spirit.</p><h2>Events Held</h2><p>The day featured a 100m sprint, long jump, relay races, football, and tug of war. Each class fielded multiple teams, and the competition was fierce yet friendly throughout.</p><h2>Winners</h2><p>Class 10 Science emerged as the overall champions, with Class 9A coming in a close second. Individual medals were awarded in all track and field categories.</p><h2>Closing Ceremony</h2><p>The event concluded with a prize distribution ceremony presided over by the Principal, Dr. Aminul Islam, who congratulated all participants for their sportsmanship and dedication.</p>','Sports','2024-01-25','https://images.unsplash.com/photo-1695049390928-ee21d41904dc?q=80&w=1584&auto=format&fit=crop&ixlib=rb-4.1.0&ixid=M3wxMjA3fDB8MHxwaG90by1wYWdlfHx8fGVufDB8fHx8fA%3D%3D','usr_admin_004',true,'2024-01-26 10:00:00+00',NULL);
INSERT INTO public.events (id,title,slug,excerpt,content,category,date,cover_image,author_id,published,created_at,author_name) VALUES ('evt_06','National Science Olympiad â€” District Round','national-science-olympiad-district-round','Four of our brightest students represented Greenfield Academy at the district round of the National Science Olympiad, bringing home two medals.','<h2>Overview</h2><p>Four students from Greenfield Academy participated in the District Round of the National Science Olympiad held on the 15th of March 2024 at Dhaka Government College. The competition drew participants from over thirty schools across the district.</p><h2>Our Participants</h2><p>Sabbir Rahman (Class 11 Science), Nusrat Jahan (Class 9B), Arif Hasan (Class 10A), and Fatema Begum (Class 9A) represented the school across three subject categories: Physics, Chemistry, and Biology.</p><h2>Results</h2><p>Sabbir Rahman secured a gold medal in the Physics category, finishing first among forty-two participants. Fatema Begum earned a silver medal in the Biology category. Both will advance to the national round scheduled for June 2024.</p><h2>Acknowledgement</h2><p>The school congratulates all four participants for their outstanding performance and thanks the science faculty, particularly Mr. Shahadat Hossain and Mrs. Fatema Khanam, for their dedicated preparation support.</p>','Academic','2024-03-15','https://images.unsplash.com/photo-1507413245164-6160d8298b31?w=1200&auto=format&fit=crop','usr_admin_004',true,'2024-03-16 09:30:00+00',NULL);
INSERT INTO public.events (id,title,slug,excerpt,content,category,date,cover_image,author_id,published,created_at,author_name) VALUES ('evt_05','Victory Day Cultural Event 2024','victory-day-cultural-event-2024','Students, teachers, and alumni gathered to celebrate Eid ul-Fitr with food, music, and the warmth of reunion after the holiday break.','<h2>Overview</h2><p>Following the Eid ul-Fitr holidays, Greenfield Academy organised a special reunion celebration on the 22nd of April 2024. The event brought together current students, teaching staff, and several alumni who returned to mark the occasion.</p><h2>Programme</h2><p>The celebration began with a communal meal featuring traditional Bangladeshi dishes prepared by the school canteen team. Students performed nasheed and folk songs, and alumni shared memories of their time at the school.</p><h2>Alumni Address</h2><p>Former student and current university lecturer Dr. Farhan Kabir delivered an inspiring address encouraging current students to pursue excellence both inside and outside the classroom. His words were met with sustained applause.</p><h2>Closing</h2><p>The Principal extended warm Eid greetings to all present and expressed hope that the spirit of togetherness displayed at the event would carry through the rest of the academic year.</p>','Cultural','2024-12-16','https://images.unsplash.com/photo-1677758017166-5bd515f200f5?w=1200&auto=format&fit=crop','usr_admin_004',true,'2024-04-23 10:00:00+00',NULL);
INSERT INTO public.events (id,title,slug,excerpt,content,category,date,cover_image,author_id,published,created_at,author_name) VALUES ('evt_03','Annual Cultural Programme 2024','annual-cultural-programme-2024','An evening of music, dance, drama, and poetry as students took to the stage to celebrate the rich cultural heritage of Bangladesh.','<h2>Overview</h2><p>The Annual Cultural Programme was held on the evening of the 5th of March in the school auditorium. Parents, guardians, and guests joined students and staff for a memorable evening of performance and celebration.</p><h2>Performances</h2><p>The programme opened with a classical dance recital by students of Class 9, followed by a short drama on the theme of environmental conservation. The highlight of the evening was a live musical performance featuring original compositions by students of Class 11.</p><h2>Poetry Recitation</h2><p>A special segment was dedicated to Bangla poetry, with students reciting works by Rabindranath Tagore and Kazi Nazrul Islam. The recitations were met with warm applause from the audience.</p><h2>Vote of Thanks</h2><p>The Vice Principal, Mrs. Hosne Ara, delivered the vote of thanks and commended the students and teachers who worked tirelessly to organise the event. The evening concluded with a group photograph of all performers.</p>','Cultural','2024-03-05','https://images.unsplash.com/photo-1514320291840-2e0a9bf2a9ae?w=1200&auto=format&fit=crop','usr_admin_001',true,'2024-03-06 08:00:00+00',NULL);
INSERT INTO public.events (id,title,slug,excerpt,content,category,date,cover_image,author_id,published,created_at,author_name) VALUES ('evt_1775741282260','About the Demo Project','about-the-demo-project','A full-stack web application built to manage students, teachers, results, attendance, schedules, and school content from a unified admin dashboard.','<h2>Overview</h2><p>This project is a full-stack school management system. It serves students, teachers, and administrators, each with their own dedicated portal and role-based access.</p><h2>Stack</h2><p>The application is built on <strong>Next.js 16</strong> App Router, <strong>React 19</strong>, and <strong>Tailwind CSS v3</strong>. The backend (BaaS) is powered by <strong>Supabase</strong> - providing a PostgreSQL database, Row Level Security, and authentication. All UI components are custom-built with no component library dependency.</p><h2>Data</h2><p>The system manages <strong>over 160 students data</strong> across multiple classes and grades, <strong>28 teaching staff</strong>, and a <strong>full academic record</strong> including results, attendance, and schedules. The database contains <strong>16 tables</strong> covering students, teachers, classes, subjects, periods, schedules, results, attendance, exams, notices, events, testimonials, and user management.</p><h2>Portals</h2><p><strong>Student Portal:</strong> students can view their class schedule, attendance record, and exam results across all subjects and terms.</p><p><strong>Teacher Portal:</strong> teachers can view their assigned class, daily schedule, and mark attendance and grade for their students.</p><p><strong>Admin Portal:</strong> role-based dashboard with five permission levels. Content management for notices, events, and testimonials. Settings restricted to admin and superadmin roles only. User management is restricted to superadmin role.</p><h2>Security &amp; Demo Restrictions</h2><p>Database writes are protected at the <strong>Row Level Security</strong> layer - only authenticated superadmin sessions can mutate data. All other portal users operate on local Storage-based sessions with no Supabase <strong>Auth token</strong>. This makes DB-level writes impossible regardless of UI access.</p><h2>Public Website</h2><p>The public-facing website includes a home page, faculty directory, events listing, notices board, and admissions form - all server-rendered and pulling <strong>live data</strong> from the database.</p>','General','2026-04-09',NULL,'30de99ad-0ecc-4caf-a115-8ca3c26cce50',true,'2026-04-09 13:28:01.584545+00',NULL);
