INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_01','Annual Sports Day 2024','We are pleased to announce that the Annual Sports Day will be held on 25th January 2024. All students are requested to participate. Events include 100m sprint, long jump, relay race, and football. Registration forms are available at the main office.','Event','high','tch_07','2024-01-10','2024-01-25');
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_02','Midterm Examination Schedule','The Midterm Examinations for all classes will commence from 1st February 2024. Students are advised to collect their admit cards from the office by 28th January. No student will be allowed to sit for exams without an admit card.','Exam','high','tch_07','2024-01-12','2024-02-15');
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_03','Library Hours Extended','The school library will now remain open from 7:30 AM to 5:00 PM on all working days. Students are encouraged to make use of the library facilities for their studies and research.','General','normal','tch_07','2024-01-14','2024-06-30');
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_04','Science Fair Registration Open','Registration for the Inter-School Science Fair 2024 is now open. Interested students from Classes 9-11 can register in teams of 2-3. Last date for registration is 20th January. Contact your class teacher for details.','Event','normal','tch_05','2024-01-15','2024-01-20');
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_05','Parent-Teacher Meeting','A Parent-Teacher meeting is scheduled for 30th January 2024. Parents of all students are requested to attend between 10:00 AM and 1:00 PM. Please bring your ward''s report card. This is a mandatory meeting.','Meeting','high','tch_07','2024-01-18','2024-01-30');
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_06','Holiday Notice â€” Eid ul-Fitr','The school will remain closed from 10th April to 18th April 2024 on the occasion of Eid ul-Fitr. Classes will resume on 19th April 2024. All students and staff are wished a joyful celebration.','Holiday','normal','tch_07','2024-04-05','2024-04-19');
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_08','New Computer Lab Inauguration','We are pleased to announce the inauguration of our new Computer Lab 2 on 1st February 2024. The lab is equipped with 30 modern workstations. ICT classes for Classes 10 and 11 will be held here starting from next week.','General','normal','tch_07','2024-01-28','2024-06-30');
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_09','Inter-School Debate Competition','Greenfield Academy will host the Inter-School Debate Competition on 10th February 2024. Students from Classes 9-11 interested in participating should register with their class teachers by 3rd February. Topic: Technology and Education.','Event','normal','tch_07','2024-01-30','2024-02-10');
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_10','School Uniform Policy Reminder','All students are reminded to wear the proper school uniform every day. Students found without proper uniform will be sent home. The policy includes white shirt, grey trousers or skirt, black shoes, and the school tie on all formal days.','General','normal','tch_07','2024-02-01','2024-12-31');
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_11','Trial Examination Notice','Trial Examinations will be held from 1st March 2024 to 10th March 2024. This is a mandatory exam for all students. Attendance during trial exams is compulsory. Results will be announced within two weeks of completion.','Exam','high','tch_07','2024-02-20','2024-03-10');
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_07','Final Examination Schedule','Final Examinations for all classes will begin on 15th May 2024. The detailed timetable has been posted on the school notice board. Students are advised to begin preparation immediately and consult their subject teachers for guidance.','Exam','high','usr_admin_001','2024-04-20','2024-05-15');
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_1775734209536','Test Notice Admin','This is a test to see if unauthorized admin perms restrictions are working. It is working from a browser without an active superadmin auth session, which is fine!!','General','normal','usr_admin_001','2026-04-09',NULL);
INSERT INTO public.notices (id,title,content,category,priority,author_id,date,expires) VALUES ('not_12','Eid ul-Adha Holiday Notice','The school will remain closed from 17th June to 22nd June 2024 on the occasion of Eid ul-Adha. Classes will resume on 23rd June 2024. Wishing all students, teachers, and staff a blessed celebration.','Holiday','normal','usr_admin_001','2026-04-01','2026-04-15');
