INSERT INTO public.testimonials (id,name,avatar,quote,child_class,active) VALUES ('tst_01','Mrs. Sharifa Begum',NULL,'Greenfield Academy has transformed my daughter completely. She was shy and unconfident when she joined. Today she leads her class and speaks with such poise. The teachers here genuinely care.','Class 9 - Section A',true);
INSERT INTO public.testimonials (id,name,avatar,quote,child_class,active) VALUES ('tst_02','Mr. Kamal Uddin',NULL,'As a parent, I wanted a school that balanced academics with character. Greenfield delivers exactly that. My son has grown not just in his grades but in his values and discipline.','Class 11 - Science',true);
INSERT INTO public.testimonials (id,name,avatar,quote,child_class,active) VALUES ('tst_03','Mrs. Roksana Islam',NULL,'The communication between school and parents is excellent. I always know how my child is getting the care he needs. It gives me great peace of mind as a working mother.','Class 10 - Section B',true);
INSERT INTO public.testimonials (id,name,avatar,quote,child_class,active) VALUES ('tst_04','Mr. Prashanta Chakraborty',NULL,'My daughter has flourished here. The science faculty in particular is outstanding. She is now preparing for the national Olympiad, something I never imagined two years ago.','Class 11 - Science',true);
INSERT INTO public.testimonials (id,name,avatar,quote,child_class,active) VALUES ('tst_06','Mr. Habibur Rahman',NULL,'The Annual Sports Day, the Science Fair, the Cultural Programme â€” these events show that Greenfield is invested in the total wellbeing of the child, not just exam results. I am proud to be part of this community.','Class 10 - Section A',true);
